<?php namespace App\Repositories\Academic;use App\Repositories\BaseRepository;use App\Models\Academic\Subject;use Illuminate\Database\Eloquent\Collection;class SubjectRepository extends BaseRepository{    public function __construct(Subject $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByName(string $name): ?Subject    {        return $this->query()->where('name', $name)->first();    }    public function findByCode(string $code): ?Subject    {        return $this->query()->where('code', $code)->first();    }    public function findByType(string $type): Collection    {        return $this->findByField('type', $type);    }    public function getActiveSubjects(): Collection    {        return $this->query()->where('is_active', true)->get();    }    public function getByCategory(string $category): Collection    {        return $this->findByField('category', $category);    }    public function searchSubjects(string $keyword): Collection    {        return $this->query()->where('name', 'like', "%{$keyword}%")->orWhere('code', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->get();    }    public function getElectiveSubjects(): Collection    {        return $this->query()->where('is_elective', true)->get();    }    public function getByTeacher(int $employeeId): Collection    {        return $this->query()->whereHas('teachers', function ($q) use ($employeeId) {                $q->where('employee_id', $employeeId);            })->get();    }}